import React, { useState, useEffect } from "react";
import axios from "axios";
import "./Admin.css";

const Admin = () => {
  const [currentTable, setCurrentTable] = useState("clients");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [modalData, setModalData] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const API_URL = "http://localhost:5000/api";

  const fetchData = async (table) => {
    setLoading(true);
    setError(null);
    try {
      const response = await axios.get(`${API_URL}/${table}`);
      setData(response.data);
    } catch (err) {
      setError("Failed to fetch data.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData(currentTable);
  }, [currentTable]);

  const handleDelete = async (id) => {
    try {
      await axios.delete(`${API_URL}/${currentTable}/${id}`);
      fetchData(currentTable);
    } catch (err) {
      setError("Failed to delete the record.");
    }
  };

  const handleSave = async (formData) => {
    try {
      if (formData.id) {
        await axios.put(`${API_URL}/${currentTable}/${formData.id}`, formData);
      } else {
        await axios.post(`${API_URL}/${currentTable}`, formData);
      }
      fetchData(currentTable);
      setIsModalOpen(false);
    } catch (err) {
      setError("Failed to save the record.");
    }
  };

  const renderTable = () => {
    if (loading) return <p>Loading...</p>;
    if (error) return <p className="error">{error}</p>;

    return (
      <table className="data-table">
        <thead>
          <tr>
            {data.length > 0 &&
              Object.keys(data[0]).map((key) => <th key={key}>{key}</th>)}
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {data.map((item) => (
            <tr key={item.id}>
              {Object.values(item).map((value, index) => (
                <td key={index}>{value}</td>
              ))}
              <td>
                <button
                  className="btn btn-edit"
                  onClick={() => {
                    setModalData(item);
                    setIsModalOpen(true);
                  }}
                >
                  Edit
                </button>
                <button
                  className="btn btn-delete"
                  onClick={() => handleDelete(item.id)}
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  const renderModal = () => {
    if (!isModalOpen) return null;

    const fields = modalData
      ? Object.keys(modalData)
      : ["first_name", "last_name", "email", "phone"];

    return (
      <div className="modal">
        <div className="modal-content">
          <h3>{modalData ? "Edit Record" : "Create Record"}</h3>
          <form
            onSubmit={(e) => {
              e.preventDefault();
              const formData = {};
              fields.forEach(
                (field) => (formData[field] = e.target[field]?.value || "")
              );
              handleSave(formData);
            }}
          >
            {fields.map((field) => (
              <div className="form-outline" key={field}>
                <label htmlFor={field}>{field}</label>
                <input
                  type="text"
                  id={field}
                  name={field}
                  defaultValue={modalData ? modalData[field] : ""}
                />
              </div>
            ))}
            <button type="submit" className="btn">
              Save
            </button>
            <button
              type="button"
              className="btn btn-cancel"
              onClick={() => setIsModalOpen(false)}
            >
              Cancel
            </button>
          </form>
        </div>
      </div>
    );
  };

  return (
    <div className="admin-panel">
      <div className="menu">
        <button
          className={`btn ${currentTable === "clients" ? "active" : ""}`}
          onClick={() => setCurrentTable("clients")}
        >
          Clients
        </button>
        <button
          className={`btn ${currentTable === "countries" ? "active" : ""}`}
          onClick={() => setCurrentTable("countries")}
        >
          Countries
        </button>
        <button
          className={`btn ${currentTable === "tours" ? "active" : ""}`}
          onClick={() => setCurrentTable("tours")}
        >
          Tours
        </button>
        <button
          className={`btn ${currentTable === "bookings" ? "active" : ""}`}
          onClick={() => setCurrentTable("bookings")}
        >
          Bookings
        </button>
      </div>
      <div className="content">
        <button
          className="btn btn-create"
          onClick={() => {
            setModalData(null);
            setIsModalOpen(true);
          }}
        >
          Create New
        </button>
        {renderTable()}
      </div>
      {renderModal()}
    </div>
  );
};

export default Admin;
